482→    #[test]
483→    fn coverage_map_save_and_load() {
484→        let dir = tempfile::tempdir().unwrap();
485→        let shatter_dir = dir.path().join(".shatter");
486→
487→        let mut map = CoverageMap::empty();
488→        map.data.entries.insert(
489→            "test_1".to_string(),
490→            TestEntry {
491→                files: BTreeMap::from([("src/main.rs".to_string(), "hash1".to_string())]),
492→            },
493→        );
494→        map.data.recorded_at = "2026-03-07".to_string();
495→        map.reverse = build_reverse_index(&map.data.entries);
496→
497→        map.save(&shatter_dir).unwrap();
498→        let loaded = CoverageMap::load(&shatter_dir).unwrap();
499→        assert_eq!(map.data, loaded.data);
