 49→/// Generate Go table-driven test source from a behavior map.
 50→///
 51→/// Each behavior becomes a test case in a table-driven `t.Run()` subtest.
 52→/// The generated file uses the standard Go testing package.
 53→///
 54→/// # Arguments
 55→/// * `behavior_map` - The behavior map to generate tests from.
 56→/// * `function_name` - The name of the function under test (used in test function name and calls).
 57→/// * `package_name` - The Go package name for the file header.
 58→pub fn generate_go_tests(
 59→    behavior_map: &BehaviorMap,
 60→    function_name: &str,
 61→    package_name: &str,
 62→) -> String {
 63→    let mut out = String::new();
 64→
 65→    out.push_str(&format!("package {package_name}\n\n"));
 66→    out.push_str("import \"testing\"\n\n");
 67→
 68→    // Test function name: TestFunctionName (capitalize first letter)
 69→    let test_func_name = format!("Test{}", capitalize_first(function_name));
 70→
 71→    out.push_str(&format!("func {test_func_name}(t *testing.T) {{\n"));
 72→
 73→    if behavior_map.behaviors.is_empty() {
 74→        out.push_str("\t// No behaviors observed\n");
 75→        out.push_str("}\n");
 76→        return out;
 77→    }
 78→
 79→    // Separate panic behaviors from normal return behaviors
 80→    let (panic_behaviors, normal_behaviors): (Vec<_>, Vec<_>) = behavior_map
 81→        .behaviors
 82→        .iter()
 83→        .partition(|b| b.thrown_error.is_some());
 84→
 85→    if !normal_behaviors.is_empty() {
 86→        out.push_str("\ttests := []struct {\n");
 87→        out.push_str("\t\tname string\n");
 88→
 89→        // Determine param types from first behavior
 90→        let first = &normal_behaviors[0];
 91→        for (i, arg) in first.input_args.iter().enumerate() {
 92→            let go_type = go_type_from_value(arg);
 93→            out.push_str(&format!("\t\targ{i}     {go_type}\n"));
 94→        }
 95→
 96→        // Determine return type from first behavior with a return value
 97→        let has_return = normal_behaviors.iter().any(|b| b.return_value.is_some());
 98→        if has_return {
 99→            let return_type = normal_behaviors
100→                .iter()
101→                .find_map(|b| b.return_value.as_ref())
102→                .map(go_type_from_value)
103→                .unwrap_or_else(|| "interface{}".to_string());
104→            out.push_str(&format!("\t\texpected {return_type}\n"));
105→        }
106→
107→        out.push_str("\t}{{\n");
108→
109→        for behavior in &normal_behaviors {
110→            let test_name = build_test_name(behavior);
111→            let args: Vec<String> = behavior.input_args.iter().map(format_go_value).collect();
112→
113→            if has_return {
114→                let expected = match &behavior.return_value {
115→                    Some(val) => format_go_value(val),
116→                    None => go_zero_value(
117→                        normal_behaviors
118→                            .iter()
119→                            .find_map(|b| b.return_value.as_ref())
120→                            .map(go_type_from_value)
121→                            .as_deref()
122→                            .unwrap_or("interface{}"),
123→                    ),
124→                };
125→                out.push_str(&format!(
126→                    "\t\t{{\"{test_name}\", {}, {expected}}},\n",
127→                    args.join(", ")
128→                ));
129→            } else {
130→                out.push_str(&format!(
131→                    "\t\t{{\"{test_name}\", {}}},\n",
132→                    args.join(", ")
133→                ));
134→            }
135→        }
136→
137→        out.push_str("\t}\n");
138→
139→        out.push_str("\tfor _, tt := range tests {\n");
140→        out.push_str("\t\tt.Run(tt.name, func(t *testing.T) {\n");
141→
142→        let arg_refs: Vec<String> = (0..normal_behaviors[0].input_args.len())
143→            .map(|i| format!("tt.arg{i}"))
144→            .collect();
145→        let call = format!("{function_name}({})", arg_refs.join(", "));
146→
147→        if has_return {
148→            out.push_str(&format!("\t\t\tgot := {call}\n"));
149→            out.push_str(&format!(
150→                "\t\t\tif got != tt.expected {{\n\t\t\t\tt.Errorf(\"{function_name}({}) = %v, want %v\", {}, got, tt.expected)\n\t\t\t}}\n",
151→                (0..normal_behaviors[0].input_args.len()).map(|_| "%v").collect::<Vec<_>>().join(", "),
152→                arg_refs.join(", "),
153→            ));
154→        } else {
155→            out.push_str(&format!("\t\t\t{call}\n"));
156→        }
157→
158→        out.push_str("\t\t})\n");
159→        out.push_str("\t}\n");
160→    }
161→
162→    // Generate panic test cases
163→    for behavior in &panic_behaviors {
164→        let test_name = build_test_name(behavior);
165→        let args: Vec<String> = behavior.input_args.iter().map(format_go_value).collect();
166→
167→        out.push_str(&format!("\tt.Run(\"{test_name}\", func(t *testing.T) {{\n"));
168→        out.push_str("\t\tdefer func() {\n");
169→        out.push_str("\t\t\tif r := recover(); r == nil {\n");
170→        out.push_str("\t\t\t\tt.Errorf(\"expected panic but did not get one\")\n");
171→        out.push_str("\t\t\t}\n");
172→        out.push_str("\t\t}()\n");
173→        out.push_str(&format!(
174→            "\t\t{function_name}({})\n",
175→            args.join(", ")
176→        ));
177→        out.push_str("\t})\n");
178→    }
179→
180→    out.push_str("}\n");
181→    out
182→}
