  1→//! Test runner abstraction for multi-language test execution.
  2→//!
  3→//! Provides a unified interface for running tests across Rust (cargo test),
  4→//! TypeScript (vitest), and Go (go test), with optional coverage instrumentation.
  5→
  6→use std::collections::BTreeMap;
  7→use std::path::{Path, PathBuf};
  8→use std::process::Command;
  9→use std::time::{Duration, Instant};
 10→
 11→use serde::{Deserialize, Serialize};
 12→
 13→use crate::test_impact::TiaError;
 14→
 15→// ---------------------------------------------------------------------------
 16→// Test tier
 17→// ---------------------------------------------------------------------------
 18→
 19→/// Test tier levels matching the project's test tier convention.
 20→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 21→#[serde(rename_all = "snake_case")]
 22→pub enum TestTier {
 23→    Quick,
 24→    Standard,
 25→    Full,
 26→    E2e,
 27→}
 28→
 29→impl TestTier {
 30→    pub fn as_str(&self) -> &'static str {
 31→        match self {
 32→            Self::Quick => "quick",
 33→            Self::Standard => "standard",
 34→            Self::Full => "full",
 35→            Self::E2e => "e2e",
 36→        }
 37→    }
 38→}
 39→
 40→impl std::fmt::Display for TestTier {
 41→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 42→        f.write_str(self.as_str())
 43→    }
 44→}
 45→
 46→impl std::str::FromStr for TestTier {
 47→    type Err = String;
 48→
 49→    fn from_str(s: &str) -> Result<Self, Self::Err> {
 50→        match s {
 51→            "quick" => Ok(Self::Quick),
 52→            "standard" => Ok(Self::Standard),
 53→            "full" => Ok(Self::Full),
 54→            "e2e" => Ok(Self::E2e),
 55→            other => Err(format!("unknown tier: {other}")),
 56→        }
 57→    }
 58→}
 59→
 60→// ---------------------------------------------------------------------------
 61→// Runner kind
 62→// ---------------------------------------------------------------------------
 63→
 64→/// Identifies which test runner to use.
 65→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 66→pub enum RunnerKind {
 67→    Cargo,
 68→    Vitest,
 69→    GoTest,
 70→}
 71→
 72→impl std::fmt::Display for RunnerKind {
 73→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 74→        match self {
 75→            Self::Cargo => f.write_str("cargo"),
 76→            Self::Vitest => f.write_str("vitest"),
 77→            Self::GoTest => f.write_str("go-test"),
 78→        }
 79→    }
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Results
 84→// ---------------------------------------------------------------------------
 85→
 86→/// Result of a test run.
 87→#[derive(Debug)]
 88→pub struct TestRunResult {
 89→    pub success: bool,
 90→    pub runner: RunnerKind,
 91→    pub duration: Duration,
 92→    pub stdout: String,
 93→    pub stderr: String,
 94→}
 95→
 96→/// Coverage data from a test run with instrumentation.
 97→#[derive(Debug)]
 98→pub struct CoverageOutput {
 99→    /// Test identifier → list of source files it touches (relative paths).
100→    pub test_file_map: BTreeMap<String, Vec<String>>,
101→    pub run_result: TestRunResult,
102→}
103→
104→// ---------------------------------------------------------------------------
105→// Runner detection
106→// ---------------------------------------------------------------------------
107→
108→/// Detected test runner with its project root.
109→#[derive(Debug)]
110→pub struct DetectedRunner {
111→    pub kind: RunnerKind,
112→    pub root: PathBuf,
113→}
114→
115→/// Auto-detect available test runners by looking for manifest files.
116→pub fn detect_runners(root: &Path) -> Vec<DetectedRunner> {
117→    let mut runners = Vec::new();
118→
119→    if root.join("Cargo.toml").exists() {
120→        runners.push(DetectedRunner {
121→            kind: RunnerKind::Cargo,
122→            root: root.to_path_buf(),
123→        });
124→    }
125→    if root.join("package.json").exists() {
126→        runners.push(DetectedRunner {
127→            kind: RunnerKind::Vitest,
128→            root: root.to_path_buf(),
129→        });
130→    }
131→    if root.join("go.mod").exists() {
132→        runners.push(DetectedRunner {
133→            kind: RunnerKind::GoTest,
134→            root: root.to_path_buf(),
135→        });
136→    }
137→
138→    // Also check subdirectories for multi-crate/multi-package repos
139→    if let Ok(entries) = std::fs::read_dir(root) {
140→        for entry in entries.flatten() {
141→            let path = entry.path();
142→            if !path.is_dir() {
143→                continue;
144→            }
145→            let dir_name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
146→            // Skip hidden dirs, target, node_modules
147→            if dir_name.starts_with('.') || dir_name == "target" || dir_name == "node_modules" {
148→                continue;
149→            }
150→
151→            if path.join("Cargo.toml").exists()
152→                && !runners.iter().any(|r| r.kind == RunnerKind::Cargo && r.root == path)
153→            {
154→                // Skip sub-crates if root has Cargo.toml (workspace handles them)
155→                // Only add if no root-level Cargo.toml
156→                if !root.join("Cargo.toml").exists() {
157→                    runners.push(DetectedRunner {
158→                        kind: RunnerKind::Cargo,
159→                        root: path.clone(),
160→                    });
161→                }
162→            }
163→            if path.join("package.json").exists()
164→                && !runners.iter().any(|r| r.kind == RunnerKind::Vitest && r.root == path)
165→            {
166→                runners.push(DetectedRunner {
167→                    kind: RunnerKind::Vitest,
168→                    root: path.clone(),
169→                });
170→            }
171→            if path.join("go.mod").exists()
172→                && !runners.iter().any(|r| r.kind == RunnerKind::GoTest && r.root == path)
173→            {
174→                runners.push(DetectedRunner {
175→                    kind: RunnerKind::GoTest,
176→                    root: path,
177→                });
178→            }
179→        }
180→    }
181→
182→    runners
183→}
184→
185→// ---------------------------------------------------------------------------
186→// Test execution
187→// ---------------------------------------------------------------------------
188→
189→/// Run tests for a given runner, optionally filtered.
190→pub fn run_tests(
191→    runner: &DetectedRunner,
192→    filter: &[String],
193→) -> Result<TestRunResult, TiaError> {
194→    let start = Instant::now();
195→
196→    let output = match runner.kind {
197→        RunnerKind::Cargo => {
198→            let mut cmd = Command::new("cargo");
199→            cmd.arg("test").current_dir(&runner.root);
200→            if !filter.is_empty() {
201→                // cargo test accepts test name filters as positional args after --
202→                cmd.arg("--");
203→                for f in filter {
204→                    cmd.arg(f);
205→                }
206→            }
207→            cmd.output()
208→        }
209→        RunnerKind::Vitest => {
210→            let mut cmd = Command::new("npx");
211→            cmd.args(["vitest", "run"]).current_dir(&runner.root);
212→            for f in filter {
213→                cmd.arg(f);
214→            }
215→            cmd.output()
216→        }
217→        RunnerKind::GoTest => {
218→            let mut cmd = Command::new("go");
219→            cmd.args(["test", "./..."]).current_dir(&runner.root);
220→            if !filter.is_empty() {
221→                let pattern = filter.join("|");
222→                cmd.args(["-run", &pattern]);
223→            }
224→            cmd.output()
225→        }
226→    };
227→
228→    let output = output.map_err(|e| TiaError::Runner {
229→        message: format!("failed to start {}: {e}", runner.kind),
230→    })?;
231→
232→    Ok(TestRunResult {
233→        success: output.status.success(),
234→        runner: runner.kind,
235→        duration: start.elapsed(),
236→        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
237→        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
238→    })
239→}
240→
241→/// Run tests with coverage instrumentation, parsing coverage output into
242→/// a test→files mapping.
243→pub fn run_with_coverage(
244→    runner: &DetectedRunner,
245→    project_root: &Path,
246→) -> Result<CoverageOutput, TiaError> {
247→    match runner.kind {
248→        RunnerKind::Cargo => run_cargo_with_coverage(&runner.root, project_root),
249→        RunnerKind::GoTest => run_go_with_coverage(&runner.root, project_root),
250→        RunnerKind::Vitest => run_vitest_with_coverage(&runner.root, project_root),
251→    }
252→}
253→
254→// ---------------------------------------------------------------------------
255→// Cargo coverage
256→// ---------------------------------------------------------------------------
257→
258→fn run_cargo_with_coverage(
259→    crate_root: &Path,
260→    project_root: &Path,
261→) -> Result<CoverageOutput, TiaError> {
262→    let start = Instant::now();
263→
264→    // Run cargo test with source-based coverage
265→    let output = Command::new("cargo")
266→        .args(["test"])
267→        .env("RUSTFLAGS", "-C instrument-coverage")
268→        .env("LLVM_PROFILE_FILE", crate_root.join("target/coverage/%p-%m.profraw").to_string_lossy().as_ref())
269→        .current_dir(crate_root)
270→        .output()
271→        .map_err(|e| TiaError::Runner {
272→            message: format!("cargo test failed: {e}"),
273→        })?;
274→
275→    let run_result = TestRunResult {
276→        success: output.status.success(),
277→        runner: RunnerKind::Cargo,
278→        duration: start.elapsed(),
279→        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
280→        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
281→    };
282→
283→    // For Cargo, we use a simplified mapping: all tests → all source files in the crate.
284→    // Full per-test file mapping requires cargo-llvm-cov or nextest which may not be available.
285→    let test_file_map = build_cargo_file_map(crate_root, project_root);
286→
287→    Ok(CoverageOutput {
288→        test_file_map,
289→        run_result,
290→    })
291→}
292→
293→/// Build a simplified test→file map for a Cargo crate by scanning source files.
294→/// Maps the crate name (as test identifier) to all .rs files in src/.
295→fn build_cargo_file_map(
296→    crate_root: &Path,
297→    project_root: &Path,
298→) -> BTreeMap<String, Vec<String>> {
299→    let mut map = BTreeMap::new();
300→    let crate_name = crate_root
301→        .file_name()
302→        .and_then(|n| n.to_str())
303→        .unwrap_or("unknown");
304→
305→    let src_dir = crate_root.join("src");
306→    if let Ok(files) = collect_rs_files(&src_dir) {
307→        let relative_files: Vec<String> = files
308→            .iter()
309→            .filter_map(|f| f.strip_prefix(project_root).ok())
310→            .map(|p| p.to_string_lossy().to_string())
311→            .collect();
312→        if !relative_files.is_empty() {
313→            map.insert(format!("{crate_name}::all"), relative_files);
314→        }
315→    }
316→
317→    map
318→}
319→
320→fn collect_rs_files(dir: &Path) -> Result<Vec<PathBuf>, std::io::Error> {
321→    let mut files = Vec::new();
322→    if !dir.exists() {
323→        return Ok(files);
324→    }
325→    for entry in std::fs::read_dir(dir)? {
326→        let entry = entry?;
327→        let path = entry.path();
328→        if path.is_dir() {
329→            files.extend(collect_rs_files(&path)?);
330→        } else if path.extension().is_some_and(|e| e == "rs") {
331→            files.push(path);
332→        }
333→    }
334→    Ok(files)
335→}
336→
337→// ---------------------------------------------------------------------------
338→// Go coverage
339→// ---------------------------------------------------------------------------
340→
341→fn run_go_with_coverage(
342→    go_root: &Path,
343→    project_root: &Path,
344→) -> Result<CoverageOutput, TiaError> {
345→    let start = Instant::now();
346→    let cover_file = go_root.join("coverage.out");
347→
348→    let output = Command::new("go")
349→        .args([
350→            "test",
351→            "./...",
352→            &format!("-coverprofile={}", cover_file.to_string_lossy()),
353→        ])
354→        .current_dir(go_root)
355→        .output()
356→        .map_err(|e| TiaError::Runner {
357→            message: format!("go test failed: {e}"),
358→        })?;
359→
360→    let run_result = TestRunResult {
361→        success: output.status.success(),
362→        runner: RunnerKind::GoTest,
363→        duration: start.elapsed(),
364→        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
365→        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
366→    };
367→
368→    let test_file_map = if cover_file.exists() {
369→        parse_go_coverprofile(&cover_file, go_root, project_root)
370→    } else {
371→        BTreeMap::new()
372→    };
373→
374→    // Clean up coverage file
375→    let _ = std::fs::remove_file(&cover_file);
376→
377→    Ok(CoverageOutput {
378→        test_file_map,
379→        run_result,
380→    })
381→}
382→
383→/// Parse Go coverprofile format into a test→files map.
384→/// Go coverprofile lines look like: `package/file.go:line.col,line.col count`
385→/// We group all covered files under the Go module's test identifier.
386→pub fn parse_go_coverprofile(
387→    cover_file: &Path,
388→    go_root: &Path,
389→    project_root: &Path,
390→) -> BTreeMap<String, Vec<String>> {
391→    let mut map = BTreeMap::new();
392→    let contents = match std::fs::read_to_string(cover_file) {
393→        Ok(c) => c,
394→        Err(_) => return map,
395→    };
396→
397→    let module_name = go_root
398→        .file_name()
399→        .and_then(|n| n.to_str())
400→        .unwrap_or("go");
401→
402→    let mut files = std::collections::HashSet::new();
403→    for line in contents.lines() {
404→        if line.starts_with("mode:") {
405→            continue;
406→        }
407→        // Format: <import-path>/<file>:<start>.<col>,<end>.<col> <count>
408→        if let Some(colon_pos) = line.find(':') {
409→            let file_path = &line[..colon_pos];
410→            // Convert import path to relative path
411→            // e.g., "github.com/user/repo/pkg/file.go" → find the .go file relative to project
412→            if let Some(go_file) = file_path.rsplit('/').next() {
413→                // Try to find this file relative to go_root
414→                let candidates = find_go_file(go_root, go_file);
415→                for candidate in candidates {
416→                    if let Ok(rel) = candidate.strip_prefix(project_root) {
417→                        files.insert(rel.to_string_lossy().to_string());
418→                    }
419→                }
420→            }
421→        }
422→    }
423→
424→    if !files.is_empty() {
425→        let mut file_list: Vec<String> = files.into_iter().collect();
426→        file_list.sort();
427→        map.insert(format!("{module_name}::all"), file_list);
428→    }
429→
430→    map
431→}
432→
433→fn find_go_file(root: &Path, filename: &str) -> Vec<PathBuf> {
434→    let mut results = Vec::new();
435→    if let Ok(entries) = std::fs::read_dir(root) {
436→        for entry in entries.flatten() {
437→            let path = entry.path();
438→            if path.is_dir() {
439→                let name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
440→                if !name.starts_with('.') && name != "vendor" {
441→                    results.extend(find_go_file(&path, filename));
442→                }
443→            } else if path.file_name().is_some_and(|n| n == filename) {
444→                results.push(path);
445→            }
446→        }
447→    }
448→    results
449→}
450→
451→// ---------------------------------------------------------------------------
452→// Vitest coverage
453→// ---------------------------------------------------------------------------
454→
455→fn run_vitest_with_coverage(
456→    ts_root: &Path,
457→    project_root: &Path,
458→) -> Result<CoverageOutput, TiaError> {
459→    let start = Instant::now();
460→
461→    let output = Command::new("npx")
462→        .args(["vitest", "run", "--coverage", "--coverage.reporter=json"])
463→        .current_dir(ts_root)
464→        .output()
465→        .map_err(|e| TiaError::Runner {
466→            message: format!("vitest failed: {e}"),
467→        })?;
468→
469→    let run_result = TestRunResult {
470→        success: output.status.success(),
471→        runner: RunnerKind::Vitest,
472→        duration: start.elapsed(),
473→        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
474→        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
475→    };
476→
477→    // Parse Istanbul coverage JSON if available
478→    let coverage_file = ts_root.join("coverage/coverage-final.json");
479→    let test_file_map = if coverage_file.exists() {
480→        parse_istanbul_coverage(&coverage_file, project_root)
481→    } else {
482→        BTreeMap::new()
483→    };
484→
485→    Ok(CoverageOutput {
486→        test_file_map,
487→        run_result,
488→    })
489→}
490→
491→/// Parse Istanbul coverage-final.json into a test→files map.
492→/// The JSON keys are absolute file paths; values contain coverage data.
493→/// We group all covered files under a single test identifier.
494→pub fn parse_istanbul_coverage(
495→    coverage_file: &Path,
496→    project_root: &Path,
497→) -> BTreeMap<String, Vec<String>> {
498→    let mut map = BTreeMap::new();
499→    let contents = match std::fs::read_to_string(coverage_file) {
500→        Ok(c) => c,
501→        Err(_) => return map,
502→    };
503→
504→    let parsed: serde_json::Value = match serde_json::from_str(&contents) {
505→        Ok(v) => v,
506→        Err(_) => return map,
507→    };
508→
509→    let ts_root = coverage_file
510→        .parent()
511→        .and_then(|p| p.parent())
512→        .and_then(|p| p.file_name())
513→        .and_then(|n| n.to_str())
514→        .unwrap_or("ts");
515→
516→    if let Some(obj) = parsed.as_object() {
517→        let mut files = Vec::new();
518→        for key in obj.keys() {
519→            let abs_path = Path::new(key);
520→            if let Ok(rel) = abs_path.strip_prefix(project_root) {
521→                files.push(rel.to_string_lossy().to_string());
522→            }
523→        }
524→        files.sort();
525→        if !files.is_empty() {
526→            map.insert(format!("{ts_root}::all"), files);
527→        }
528→    }
529→
530→    map
531→}
532→
533→// ---------------------------------------------------------------------------
534→// Tier execution
535→// ---------------------------------------------------------------------------
536→
537→/// Run a complete test tier, returning success/failure.
538→/// Executes the tier's predefined commands in order.
539→pub fn run_tier(tier: TestTier, project_root: &Path) -> Result<bool, TiaError> {
540→    match tier {
541→        TestTier::Quick => run_tier_quick(project_root),
542→        TestTier::Standard => run_tier_standard(project_root),
543→        TestTier::Full => run_tier_full(project_root),
544→        TestTier::E2e => run_tier_e2e(project_root),
545→    }
546→}
547→
548→fn run_tier_quick(root: &Path) -> Result<bool, TiaError> {
549→    let output = Command::new("cargo")
550→        .args(["test"])
551→        .current_dir(root)
552→        .status()
553→        .map_err(|e| TiaError::Runner {
554→            message: format!("cargo test failed: {e}"),
555→        })?;
556→    Ok(output.success())
557→}
558→
559→fn run_tier_standard(root: &Path) -> Result<bool, TiaError> {
560→    if !run_tier_quick(root)? {
561→        return Ok(false);
562→    }
563→    let output = Command::new("cargo")
564→        .args(["clippy", "--", "-D", "warnings"])
565→        .current_dir(root)
566→        .status()
567→        .map_err(|e| TiaError::Runner {
568→            message: format!("cargo clippy failed: {e}"),
569→        })?;
570→    Ok(output.success())
571→}
572→
573→fn run_tier_full(root: &Path) -> Result<bool, TiaError> {
574→    if !run_tier_standard(root)? {
575→        return Ok(false);
576→    }
577→
578→    // TypeScript tests
579→    let ts_dir = root.join("shatter-ts");
580→    if ts_dir.exists() {
581→        let output = Command::new("npm")
582→            .args(["test"])
583→            .current_dir(&ts_dir)
584→            .status()
585→            .map_err(|e| TiaError::Runner {
586→                message: format!("npm test failed: {e}"),
587→            })?;
588→        if !output.success() {
589→            return Ok(false);
590→        }
591→    }
592→
593→    // Go tests
594→    let go_dir = root.join("shatter-go");
595→    if go_dir.exists() {
596→        let output = Command::new("go")
597→            .args(["test", "./..."])
598→            .current_dir(&go_dir)
599→            .status()
600→            .map_err(|e| TiaError::Runner {
601→                message: format!("go test failed: {e}"),
602→            })?;
603→        if !output.success() {
604→            return Ok(false);
605→        }
606→    }
607→
608→    Ok(true)
609→}
610→
611→fn run_tier_e2e(root: &Path) -> Result<bool, TiaError> {
612→    if !run_tier_full(root)? {
613→        return Ok(false);
614→    }
615→    let output = Command::new("cargo")
616→        .args(["test", "--test", "e2e_concolic"])
617→        .current_dir(root)
618→        .status()
619→        .map_err(|e| TiaError::Runner {
620→            message: format!("e2e test failed: {e}"),
621→        })?;
622→    Ok(output.success())
623→}
624→
625→// ---------------------------------------------------------------------------
626→// Git helpers
627→// ---------------------------------------------------------------------------
628→
629→/// Get the current HEAD commit hash (short form).
630→pub fn git_head_commit(root: &Path) -> Result<String, TiaError> {
631→    let output = Command::new("git")
632→        .args(["rev-parse", "--short", "HEAD"])
