        CliCommand::BuildFrontend {
            language,
            config,
            output,
        } => run_build_frontend(&language, config.as_deref(), output.as_deref())
            .map_err(|e| e.into()),
        CliCommand::Test {
            all,
            record,
            tier,
            base,
            include_untracked,
            dry_run,
            prioritize,
            budget,
        } => {
            match run_test(all, record, tier, &base, include_untracked, dry_run, prioritize, budget, use_color) {
                Ok(success) => {
                    return if success {
                        ExitCode::SUCCESS
                    } else {
                        ExitCode::FAILURE
                    };
                }
                Err(e) => Err(e),
            }
        }
        CliCommand::Stale {
            source,
            spec,
            format,
            request_timeout,
            exec_timeout,
            build_timeout,
            memory_limit,
            cache_dir,
            no_cache,
        } => {
            match run_stale(
                &source,
                &spec,
                &format,
                request_timeout,
                exec_timeout,
                build_timeout,
                memory_limit,
                log_level,
                cli.project_dir.as_deref(),
                cache_dir.as_deref(),
                no_cache,
            )
            .await
            {
                Ok(all_fresh) => {
                    if all_fresh {
                        return ExitCode::SUCCESS;
                    }
                    return ExitCode::FAILURE;
                }
                Err(e) => Err(e),
            }
        }
    };

    match result {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("Error: {e}");
            ExitCode::FAILURE
        }
    }
}

/// Run tests with impact analysis, tier execution, or coverage recording.
fn run_test(
    all: bool,
    record: bool,
    tier: Option<String>,
    base: &str,
    include_untracked: bool,
    dry_run: bool,
    prioritize_flag: bool,
    budget: Option<String>,
    use_color: bool,
) -> Result<bool, Box<dyn std::error::Error>> {
    let project_root = std::env::current_dir()?;
    let shatter_dir = project_root.join(".shatter");

    // --- Tier mode: run predefined tier commands ---
    if let Some(tier_str) = &tier {
        let tier_val: TestTier = tier_str
            .parse()
            .map_err(|e: String| -> Box<dyn std::error::Error> { e.into() })?;
        eprintln!("Running {} tier...", tier_val);
        let success = test_runner::run_tier(tier_val, &project_root)?;
        if success {
            let commit = test_runner::git_head_commit(&project_root).unwrap_or_default();
            test_impact::write_tier_marker(&shatter_dir, tier_val.as_str(), &commit)?;
            eprintln!("Tier {tier_val} passed. Marker written.");
        } else {
            eprintln!("Tier {tier_val} FAILED.");
        }
        return Ok(success);
    }

    // --- Record mode: run all tests with coverage instrumentation ---
    if record {
        eprintln!("Recording coverage...");
        let runners = test_runner::detect_runners(&project_root);
        if runners.is_empty() {
            eprintln!("No test runners detected.");
            return Ok(false);
        }

        let mut map = CoverageMap::empty();
        let mut all_success = true;

        for runner in &runners {
            eprintln!("  Running {} in {}...", runner.kind, runner.root.display());
            match test_runner::run_with_coverage(runner, &project_root) {
                Ok(coverage) => {
                    if !coverage.run_result.success {
                        eprintln!("  {} tests FAILED", runner.kind);
                        all_success = false;
                    }
                    map.update_from_coverage(&coverage.test_file_map, &project_root)?;
                }
                Err(e) => {
                    eprintln!("  {} coverage failed: {e}", runner.kind);
                    all_success = false;
                }
            }
        }

        map.save(&shatter_dir)?;
        eprintln!(
            "Coverage map saved ({} test entries).",
            map.data.entries.len()
        );
        return Ok(all_success);
    }

    // --- All mode: run all tests without filtering ---
    if all {
        eprintln!("Running all tests...");
        let runners = test_runner::detect_runners(&project_root);
        let mut all_success = true;
        for runner in &runners {
            eprintln!("  Running {} in {}...", runner.kind, runner.root.display());
            let result = test_runner::run_tests(runner, &[])?;
            if !result.success {
                eprintln!("  {} FAILED ({:.1}s)", runner.kind, result.duration.as_secs_f64());
                all_success = false;
            } else {
                eprintln!("  {} passed ({:.1}s)", runner.kind, result.duration.as_secs_f64());
            }
        }
        return Ok(all_success);
    }

    // --- Default: impact analysis ---
    let map = match CoverageMap::load(&shatter_dir) {
        Ok(m) => m,
        Err(test_impact::TiaError::NoCoverageMap { .. }) => {
            eprintln!("No coverage map found. Run `shatter test --record` first to build one.");
            return Ok(false);
        }
        Err(e) => return Err(e.into()),
    };

    let scm_provider = shatter_core::scm::detect_provider(&project_root)?;
    use shatter_core::scm::ScmProvider;
    let changed = if base == "HEAD" {
        scm_provider.changed_files(&project_root, include_untracked)?
    } else {
        let mut files = scm_provider.diff_files(&project_root, base)?;
        if include_untracked {
            let uncommitted = scm_provider.changed_files(&project_root, true)?;
            for f in uncommitted {
                if !files.contains(&f) {
                    files.push(f);
                }
            }
        }
        files
    };

    // Convert to relative paths
    let changed_relative: Vec<String> = changed
        .iter()
        .filter_map(|p| p.strip_prefix(&project_root).ok())
        .map(|p| p.to_string_lossy().to_string())
        .collect();

    if changed_relative.is_empty() {
        eprintln!("No changed files detected. Nothing to test.");
        return Ok(true);
    }

    let query = map.query_affected(&changed_relative);

    if dry_run {
        let header = format!("{} changed file(s), {} affected test(s):",
            query.changed_files.len(),
            query.affected_tests.len());
        if use_color {
            eprintln!("\x1b[1m{header}\x1b[0m");
        } else {
            eprintln!("{header}");
        }
        eprintln!();
        eprintln!("Changed files:");
        for f in &query.changed_files {
            eprintln!("  {f}");
        }
        eprintln!();
        eprintln!("Affected tests:");
        for t in &query.affected_tests {
            eprintln!("  {t}");
        }
        if !query.unmapped_files.is_empty() {
            eprintln!();
            eprintln!("Unmapped files (not in coverage map):");
            for f in &query.unmapped_files {
                eprintln!("  {f}");
            }
        }
        return Ok(true);
    }

    if query.affected_tests.is_empty() {
        if query.unmapped_files.is_empty() {
            eprintln!("No affected tests found. All changes are in untested files.");
        } else {
            eprintln!(
                "No affected tests found. {} file(s) not in coverage map — consider `shatter test --record`.",
                query.unmapped_files.len()
            );
        }
        return Ok(true);
    }

    eprintln!(
        "Running {} affected test(s) for {} changed file(s)...",
        query.affected_tests.len(),
        query.changed_files.len()
    );

    let runners = test_runner::detect_runners(&project_root);
    let mut all_success = true;
    for runner in &runners {
        // Filter tests relevant to this runner
        let runner_prefix = match runner.kind {
            test_runner::RunnerKind::Cargo => "",
            test_runner::RunnerKind::Vitest => "shatter-ts",
            test_runner::RunnerKind::GoTest => "shatter-go",
        };

        let runner_tests: Vec<String> = if runner_prefix.is_empty() {
            query.affected_tests.clone()
        } else {
            query
                .affected_tests
                .iter()
                .filter(|t| t.contains(runner_prefix))
                .cloned()
                .collect()
        };

        if runner_tests.is_empty() {
            continue;
        }

        eprintln!("  Running {} ({} test(s))...", runner.kind, runner_tests.len());
        let result = test_runner::run_tests(runner, &runner_tests)?;
        if !result.success {
            eprintln!("  {} FAILED ({:.1}s)", runner.kind, result.duration.as_secs_f64());
            all_success = false;
        } else {
            eprintln!("  {} passed ({:.1}s)", runner.kind, result.duration.as_secs_f64());
        }
    }

    Ok(all_success)
}

/// Build a custom frontend binary with user-provided native generators.
fn run_build_frontend(
    language: &str,
    config_dir: Option<&Path>,
    output_dir: Option<&Path>,
) -> Result<(), String> {
    let shatter_dir = config_dir
        .map(PathBuf::from)
        .or_else(|| {
            let candidate = PathBuf::from(".shatter");
            candidate.is_dir().then_some(candidate)
        })
        .ok_or_else(|| "no .shatter/ directory found; pass --config or run from project root".to_string())?;

    let config_path = shatter_dir.join("config.yaml");
    if !config_path.exists() {
        return Err(format!(
            "config not found: {}",
            config_path.display()
        ));
    }

    let config = shatter_config::parse_config(&config_path)
        .map_err(|e| format!("failed to load config: {e}"))?;

    let out_dir = output_dir
        .map(PathBuf::from)
        .unwrap_or_else(|| shatter_dir.join("bin"));

    std::fs::create_dir_all(&out_dir)
        .map_err(|e| format!("failed to create output dir: {e}"))?;

    match language {
        "go" => build_go_frontend(&shatter_dir, &config, &out_dir),
        "rust" => build_rust_frontend(&shatter_dir, &config, &out_dir),
        other => Err(format!(
            "unsupported language '{other}'; supported: go, rust"
        )),
    }
}

/// Collect native generator file paths from config for a given language extension.
fn collect_native_generators(
    config: &ShatterConfig,
    extension: &str,
) -> Vec<(String, PathBuf)> {
    let mut generators = Vec::new();
    let check = |name: &str, path_str: &str| {
        let path = Path::new(path_str);
        if path.extension().and_then(|e| e.to_str()) == Some(extension) {
            Some((name.to_string(), path.to_path_buf()))
        } else {
            None
        }
    };

    if let Some(ref type_gens) = config.defaults.generators {
        for (name, path_str) in type_gens {
            if let Some(entry) = check(name, path_str) {
                generators.push(entry);
            }
        }
    }
    if let Some(ref param_gens) = config.defaults.param_generators {
        for (name, path_str) in param_gens {
            if let Some(entry) = check(name, path_str) {
                generators.push(entry);
            }
        }
    }
    generators
}

/// Build a custom Go frontend binary with native generators compiled in.
///
/// Creates a temporary Go module that imports shatter-go's protocol handler and
/// the user's generator files, wires them into the registry, then builds a single
/// binary. Inspired by the xcaddy pattern: replace directives point to local source.
fn build_go_frontend(
    shatter_dir: &Path,
    config: &ShatterConfig,
    out_dir: &Path,
) -> Result<(), String> {
    let native_gens = collect_native_generators(config, "go");
    if native_gens.is_empty() {
        return Err(
            "no .go generators found in config.yaml; nothing to build".to_string(),
        );
    }

    let output_binary = out_dir.join("shatter-go-custom");
    log::info!(
        "building custom Go frontend with {} native generator(s)...",
        native_gens.len()
    );

    // Locate the shatter-go source directory. In development it's a sibling of
    // shatter-cli; for installed binaries it would be embedded (future work).
    let shatter_go_dir = locate_shatter_go_source()
        .ok_or_else(|| "cannot find shatter-go source directory; \
            ensure you are running from the shatter repo or set SHATTER_GO_SRC".to_string())?;

    // Create temp build directory
    let temp_dir = tempfile::tempdir()
        .map_err(|e| format!("failed to create temp dir: {e}"))?;
    let build_dir = temp_dir.path();

    // Initialize Go module
    run_go_cmd(build_dir, &["mod", "init", "shatter-custom-frontend"])?;

    // Copy user generator files into a usergens/ package in the build dir.
    let usergens_dir = build_dir.join("usergens");
    std::fs::create_dir_all(&usergens_dir)
        .map_err(|e| format!("failed to create usergens dir: {e}"))?;

    // Resolve generator file paths and copy them
    let project_root = shatter_dir.parent().unwrap_or(Path::new("."));
    for (_name, rel_path) in &native_gens {
        let src = if rel_path.is_absolute() {
            rel_path.clone()
        } else {
            project_root.join(rel_path)
        };
        let filename = src.file_name()
            .ok_or_else(|| format!("generator path has no filename: {}", src.display()))?;
        std::fs::copy(&src, usergens_dir.join(filename))
            .map_err(|e| format!("failed to copy {}: {e}", src.display()))?;
    }

    // Ensure the usergens directory has a valid package declaration.
    // Write a package file that re-exports the generator functions.
    let usergens_pkg = "package usergens\n";
    // Check if any copied file already declares `package usergens`; if not,
    // they might declare a different package. We'll write a minimal file.
    let has_package_decl = native_gens.iter().any(|(_, rel_path)| {
        let src = if rel_path.is_absolute() { rel_path.clone() } else { project_root.join(rel_path) };
        std::fs::read_to_string(&src)
            .map(|s| s.contains("package usergens"))
            .unwrap_or(false)
    });
    if !has_package_decl {
        std::fs::write(usergens_dir.join("doc.go"), usergens_pkg)
            .map_err(|e| format!("failed to write doc.go: {e}"))?;
    }

    // Generate main.go with generator registrations.
    let mut registrations = String::new();
    for (name, _) in &native_gens {
        registrations.push_str(&format!(
            "\thandler.Registry().RegisterNative(\"{name}\", usergens.{name})\n"
        ));
    }

    let main_go = format!(
        r#"package main

import (
	"fmt"
	"os"

	"github.com/shatter-dev/shatter/shatter-go/protocol"
	"shatter-custom-frontend/usergens"
)

func main() {{
	handler := protocol.NewHandler(os.Stdin, os.Stdout, os.Stderr)
{registrations}
	if err := handler.Run(); err != nil {{
		fmt.Fprintf(os.Stderr, "[shatter-go-custom] Fatal: %v\n", err)
		os.Exit(1)
	}}
}}
"#
    );

    std::fs::write(build_dir.join("main.go"), &main_go)
        .map_err(|e| format!("failed to write main.go: {e}"))?;

    // Wire the local shatter-go source via replace directive.
    let shatter_go_abs = std::fs::canonicalize(&shatter_go_dir)
        .map_err(|e| format!("failed to canonicalize shatter-go path: {e}"))?;
    run_go_cmd(
        build_dir,
        &[
            "mod", "edit",
            "--require", "github.com/shatter-dev/shatter/shatter-go@v0.0.0",
            "--replace",
            &format!(
                "github.com/shatter-dev/shatter/shatter-go={}",
                shatter_go_abs.display()
            ),
        ],
    )?;

    // Resolve dependencies
    run_go_cmd(build_dir, &["mod", "tidy"])?;

    // Build the binary
    let output = std::process::Command::new("go")
        .args([
            "build",
            "-o",
            &output_binary.display().to_string(),
            "-trimpath",
            "-ldflags",
            "-w -s",
            ".",
        ])
        .current_dir(build_dir)
        .output()
        .map_err(|e| format!("failed to run `go build`: {e}"))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!("go build failed:\n{stderr}"));
    }

    log::info!(
        "custom Go frontend built: {}",
        output_binary.display()
    );
    Ok(())
}

/// Locate the shatter-go source directory for custom builds.
/// Checks: $SHATTER_GO_SRC env var, then sibling directory relative to this binary.
fn locate_shatter_go_source() -> Option<PathBuf> {
    // Check env var first
    if let Ok(src) = std::env::var("SHATTER_GO_SRC") {
        let p = PathBuf::from(src);
        if p.join("go.mod").exists() {
            return Some(p);
        }
    }

    // Check relative to cwd (development layout)
    let candidate = PathBuf::from("shatter-go");
    if candidate.join("go.mod").exists() {
        return Some(candidate);
    }

    None
}

/// Run a Go command in the given directory, returning an error on failure.
fn run_go_cmd(dir: &Path, args: &[&str]) -> Result<(), String> {
    let output = std::process::Command::new("go")
        .args(args)
        .current_dir(dir)
        .output()
        .map_err(|e| format!("failed to run `go {}`: {e}", args.join(" ")))?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!("go {} failed:\n{stderr}", args.join(" ")));
    }
    Ok(())
}

/// Build a custom Rust frontend binary with native generators compiled in.
///
/// Creates a temporary Cargo project that depends on shatter-rust and the user's
/// generator source files, generates registration code, and builds a single binary.
fn build_rust_frontend(
    shatter_dir: &Path,
    config: &ShatterConfig,
    out_dir: &Path,
) -> Result<(), String> {
    let native_gens = collect_native_generators(config, "rs");
    if native_gens.is_empty() {
        return Err(
            "no .rs generators found in config.yaml; nothing to build".to_string(),
        );
    }

    let output_binary = out_dir.join("shatter-rust-custom");
    log::info!(
        "building custom Rust frontend with {} native generator(s)...",
        native_gens.len()
    );

    // Locate shatter-rust source
    let shatter_rust_dir = locate_shatter_rust_source()
        .ok_or_else(|| "cannot find shatter-rust source directory; \
            ensure you are running from the shatter repo or set SHATTER_RUST_SRC".to_string())?;
    let shatter_rust_abs = std::fs::canonicalize(&shatter_rust_dir)
        .map_err(|e| format!("failed to canonicalize shatter-rust path: {e}"))?;

    // Create temp build directory
    let temp_dir = tempfile::tempdir()
        .map_err(|e| format!("failed to create temp dir: {e}"))?;
    let build_dir = temp_dir.path();

    // Create Cargo project structure
    let src_dir = build_dir.join("src");
    std::fs::create_dir_all(&src_dir)
        .map_err(|e| format!("failed to create src dir: {e}"))?;

    // Copy user generator files into src/
    let project_root = shatter_dir.parent().unwrap_or(Path::new("."));
    let mut mod_declarations = String::new();
    let mut registrations = String::new();
    for (name, rel_path) in &native_gens {
        let src = if rel_path.is_absolute() {
            rel_path.clone()
        } else {
            project_root.join(rel_path)
        };
        let mod_name = name.to_lowercase();
        let filename = format!("{mod_name}.rs");
        std::fs::copy(&src, src_dir.join(&filename))
            .map_err(|e| format!("failed to copy {}: {e}", src.display()))?;
        mod_declarations.push_str(&format!("mod {mod_name};\n"));
        registrations.push_str(&format!(
            "    registry.register(\"{name}\", Box::new({mod_name}::{name}));\n"
        ));
    }

    // Write Cargo.toml
    let cargo_toml = format!(
        r#"[package]
name = "shatter-rust-custom"
version = "0.1.0"
edition = "2021"

[[bin]]
name = "shatter-rust-custom"
path = "src/main.rs"

[dependencies]
shatter-rust = {{ path = "{}" }}
serde_json = "1"
"#,
        shatter_rust_abs.display()
    );
    std::fs::write(build_dir.join("Cargo.toml"), &cargo_toml)
        .map_err(|e| format!("failed to write Cargo.toml: {e}"))?;

    // Generate main.rs
    let main_rs = format!(
        r#"use shatter_rust::generators::{{NativeRegistry, GeneratorResult}};
use shatter_rust::handler::Handler;
use std::io;

{mod_declarations}
fn main() {{
    let mut registry = NativeRegistry::new();
{registrations}
    let handler = Handler::new_with_native_registry(
        io::stdin().lock(),
        io::stdout().lock(),
        io::stderr(),
        registry,
    );
    if let Err(e) = handler.run() {{
        eprintln!("[shatter-rust-custom] Fatal: {{e}}");
        std::process::exit(1);
    }}
}}
"#
    );
    std::fs::write(src_dir.join("main.rs"), &main_rs)
        .map_err(|e| format!("failed to write main.rs: {e}"))?;

    // Build
    let output = std::process::Command::new("cargo")
        .args(["build", "--release"])
        .current_dir(build_dir)
        .output()
        .map_err(|e| format!("failed to run `cargo build`: {e}"))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!("cargo build failed:\n{stderr}"));
    }

    // Copy the built binary to the output directory
    let built = build_dir
        .join("target")
        .join("release")
        .join("shatter-rust-custom");
    std::fs::copy(&built, &output_binary)
        .map_err(|e| format!("failed to copy binary: {e}"))?;

    log::info!(
        "custom Rust frontend built: {}",
        output_binary.display()
    );
    Ok(())
}

/// Locate the shatter-rust source directory for custom builds.
fn locate_shatter_rust_source() -> Option<PathBuf> {
    if let Ok(src) = std::env::var("SHATTER_RUST_SRC") {
        let p = PathBuf::from(src);
        if p.join("Cargo.toml").exists() {
            return Some(p);
        }
    }

    let candidate = PathBuf::from("shatter-rust");
    if candidate.join("Cargo.toml").exists() {
        return Some(candidate);
    }

    None
}

